[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct Style
{
    public float FontSizeBase;                     // Current base font size before external global factors are applied. Use PushFont(NULL, size) to modify. Use ImGui::GetFontSize() to obtain scaled value.
    public float FontScaleMain;                    // Main global scale factor. May be set by application once, or exposed to end-user.
    public float FontScaleDpi;                     // Additional global scale factor from viewport/monitor contents scale. In docking branch: when io.ConfigDpiScaleFonts is enabled, this is automatically overwritten when changing monitor DPI.
    public float Alpha;                            // Global alpha applies to everything in Dear ImGui.
    public float DisabledAlpha;                    // Additional alpha multiplier applied by BeginDisabled(). Multiply over current value of Alpha.
    public ImVec2 WindowPadding;                   // Padding within a window.
    public float WindowRounding;                   // Radius of window corners rounding. Set to 0.0f to have rectangular windows. Large values tend to lead to variety of artifacts and are not recommended.
    public float WindowBorderSize;                 // Thickness of border around windows. Generally set to 0.0f or 1.0f. (Other values are not well tested and more CPU/GPU costly).
    public float WindowBorderHoverPadding;         // Hit-testing extent outside/inside resizing border. Also extend determination of hovered window. Generally meaningfully larger than WindowBorderSize to make it easy to reach borders.
    public ImVec2 WindowMinSize;                   // Minimum window size. This is a global setting. If you want to constrain individual windows, use SetNextWindowSizeConstraints().
    public ImVec2 WindowTitleAlign;                // Alignment for title bar text. Defaults to (0.0f,0.5f) for left-aligned,vertically centered.
    public Dir WindowMenuButtonPosition;           // Side of the collapsing/docking button in the title bar (None/Left/Right). Defaults to ImGuiDir_Left.
    public float ChildRounding;                    // Radius of child window corners rounding. Set to 0.0f to have rectangular windows.
    public float ChildBorderSize;                  // Thickness of border around child windows. Generally set to 0.0f or 1.0f. (Other values are not well tested and more CPU/GPU costly).
    public float PopupRounding;                    // Radius of popup window corners rounding. (Note that tooltip windows use WindowRounding)
    public float PopupBorderSize;                  // Thickness of border around popup/tooltip windows. Generally set to 0.0f or 1.0f. (Other values are not well tested and more CPU/GPU costly).
    public ImVec2 FramePadding;                    // Padding within a framed rectangle (used by most widgets).
    public float FrameRounding;                    // Radius of frame corners rounding. Set to 0.0f to have rectangular frame (used by most widgets).
    public float FrameBorderSize;                  // Thickness of border around frames. Generally set to 0.0f or 1.0f. (Other values are not well tested and more CPU/GPU costly).
    public ImVec2 ItemSpacing;                     // Horizontal and vertical spacing between widgets/lines.
    public ImVec2 ItemInnerSpacing;                // Horizontal and vertical spacing between within elements of a composed widget (e.g. a slider and its label).
    public ImVec2 CellPadding;                     // Padding within a table cell. Cellpadding.x is locked for entire table. CellPadding.y may be altered between different rows.
    public ImVec2 TouchExtraPadding;               // Expand reactive bounding box for touch-based system where touch position is not accurate enough. Unfortunately we don't sort widgets so priority on overlap will always be given to the first widget. So don't grow this too much!
    public float IndentSpacing;                    // Horizontal indentation when e.g. entering a tree node. Generally == (FontSize + FramePadding.x*2).
    public float ColumnsMinSpacing;                // Minimum horizontal spacing between two columns. Preferably > (FramePadding.x + 1).
    public float ScrollbarSize;                    // Width of the vertical scrollbar, Height of the horizontal scrollbar.
    public float ScrollbarRounding;                // Radius of grab corners for scrollbar.
    public float ScrollbarPadding;                 // Padding of scrollbar grab within its frame (same for both axes).
    public float GrabMinSize;                      // Minimum width/height of a grab box for slider/scrollbar.
    public float GrabRounding;                     // Radius of grabs corners rounding. Set to 0.0f to have rectangular slider grabs.
    public float LogSliderDeadzone;                // The size in pixels of the dead-zone around zero on logarithmic sliders that cross zero.
    public float ImageRounding;                    // Rounding of Image() calls.
    public float ImageBorderSize;                  // Thickness of border around Image() calls.
    public float TabRounding;                      // Radius of upper corners of a tab. Set to 0.0f to have rectangular tabs.
    public float TabBorderSize;                    // Thickness of border around tabs.
    public float TabMinWidthBase;                  // Minimum tab width, to make tabs larger than their contents. TabBar buttons are not affected.
    public float TabMinWidthShrink;                // Minimum tab width after shrinking, when using ImGuiTabBarFlags_FittingPolicyMixed policy.
    public float TabCloseButtonMinWidthSelected;   // -1: always visible. 0.0f: visible when hovered. >0.0f: visible when hovered if minimum width.
    public float TabCloseButtonMinWidthUnselected; // -1: always visible. 0.0f: visible when hovered. >0.0f: visible when hovered if minimum width. FLT_MAX: never show close button when unselected.
    public float TabBarBorderSize;                 // Thickness of tab-bar separator, which takes on the tab active color to denote focus.
    public float TabBarOverlineSize;               // Thickness of tab-bar overline, which highlights the selected tab-bar.
    public float TableAngledHeadersAngle;          // Angle of angled headers (supported values range from -50.0f degrees to +50.0f degrees).
    public ImVec2 TableAngledHeadersTextAlign;     // Alignment of angled headers within the cell
    public TreeNodeFlags TreeLinesFlags;           // Default way to draw lines connecting TreeNode hierarchy. ImGuiTreeNodeFlags_DrawLinesNone or ImGuiTreeNodeFlags_DrawLinesFull or ImGuiTreeNodeFlags_DrawLinesToNodes.
    public float TreeLinesSize;                    // Thickness of outlines when using ImGuiTreeNodeFlags_DrawLines.
    public float TreeLinesRounding;                // Radius of lines connecting child nodes to the vertical line.
    public float DragDropTargetRounding;           // Radius of the drag and drop target frame.
    public float DragDropTargetBorderSize;         // Thickness of the drag and drop target border.
    public float DragDropTargetPadding;            // Size to expand the drag and drop target from actual target item size.
    public float ColorMarkerSize;                  // Size of R/G/B/A color markers for ColorEdit4() and for Drags/Sliders when using ImGuiSliderFlags_ColorMarkers.
    public Dir ColorButtonPosition;                // Side of the color button in the ColorEdit4 widget (left/right). Defaults to ImGuiDir_Right.
    public ImVec2 ButtonTextAlign;                 // Alignment of button text when button is larger than text. Defaults to (0.5f, 0.5f) (centered).
    public ImVec2 SelectableTextAlign;             // Alignment of selectable text. Defaults to (0.0f, 0.0f) (top-left aligned). It's generally important to keep this left-aligned if you want to lay multiple items on a same line.
    public float SeparatorSize;                    // Thickness of border in Separator()
    public float SeparatorTextBorderSize;          // Thickness of border in SeparatorText()
    public ImVec2 SeparatorTextAlign;              // Alignment of text within the separator. Defaults to (0.0f, 0.5f) (left aligned, center).
    public ImVec2 SeparatorTextPadding;            // Horizontal offset of text from each edge of the separator + spacing on other axis. Generally small values. .y is recommended to be == FramePadding.y.
    public ImVec2 DisplayWindowPadding;            // Apply to regular windows: amount which we enforce to keep visible when moving near edges of your screen.
    public ImVec2 DisplaySafeAreaPadding;          // Apply to every windows, menus, popups, tooltips: amount where we avoid displaying contents. Adjust if you cannot see the edges of your screen (e.g. on a TV where scaling has not been configured).
    public byte DockingNodeHasCloseButton;         // Docking node has their own CloseButton() to close all docked windows.
    public float DockingSeparatorSize;             // Thickness of resizing border between docked windows
    public float MouseCursorScale;                 // Scale software rendered mouse cursor (when io.MouseDrawCursor is enabled). We apply per-monitor DPI scaling over this scale. May be removed later.
    public byte AntiAliasedLines;                  // Enable anti-aliased lines/borders. Disable if you are really tight on CPU/GPU. Latched at the beginning of the frame (copied to ImDrawList).
    public byte AntiAliasedLinesUseTex;            // Enable anti-aliased lines/borders using textures where possible. Require backend to render with bilinear filtering (NOT point/nearest filtering). Latched at the beginning of the frame (copied to ImDrawList).
    public byte AntiAliasedFill;                   // Enable anti-aliased edges around filled shapes (rounded rectangles, circles, etc.). Disable if you are really tight on CPU/GPU. Latched at the beginning of the frame (copied to ImDrawList).
    public float CurveTessellationTol;             // Tessellation tolerance when using PathBezierCurveTo() without a specific number of segments. Decrease for highly tessellated curves (higher quality, more polygons), increase to reduce quality.
    public float CircleTessellationMaxError;       // Maximum error (in pixels) allowed when using AddCircle()/AddCircleFilled() or drawing rounded corner rectangles with no explicit segment count specified. Decrease for higher quality but more geometry.
    public Style_Colors_Array Colors;
    public float HoverStationaryDelay;             // Delay for IsItemHovered(ImGuiHoveredFlags_Stationary). Time required to consider mouse stationary.
    public float HoverDelayShort;                  // Delay for IsItemHovered(ImGuiHoveredFlags_DelayShort). Usually used along with HoverStationaryDelay.
    public float HoverDelayNormal;                 // Delay for IsItemHovered(ImGuiHoveredFlags_DelayNormal). "
    public HoveredFlags HoverFlagsForTooltipMouse; // Default flags when using IsItemHovered(ImGuiHoveredFlags_ForTooltip) or BeginItemTooltip()/SetItemTooltip() while using mouse.
    public HoveredFlags HoverFlagsForTooltipNav;   // Default flags when using IsItemHovered(ImGuiHoveredFlags_ForTooltip) or BeginItemTooltip()/SetItemTooltip() while using keyboard/gamepad.
    public float _MainScale;                       // FIXME-WIP: Reference scale, as applied by ScaleAllSizes(). PLEASE DO NOT USE THIS FOR NOW.
    public float _NextFrameFontSizeBase;           // FIXME: Temporary hack until we finish remaining work.
}

/// <summary>
/// [Internal] Storage used by IsKeyDown(), IsKeyPressed() etc functions.
/// If prior to 1.87 you used io.KeysDownDuration[] (which was marked as internal), you should use GetKeyData(key)-&gt;DownDuration and *NOT* io.KeysData[key]-&gt;DownDuration.
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public partial struct KeyData
{
    public byte Down;              // True for if key is down
    public float DownDuration;     // Duration the key has been down (<0.0f: not pressed, 0.0f: just pressed, >0.0f: time held)
    public float DownDurationPrev; // Last frame duration the key has been down
    public float AnalogValue;      // 0.0f..1.0f for gamepad values
}

