    public byte ConfigNavEscapeClearFocusItem;                       // = true           // Pressing Escape can clear focused item + navigation id/highlight. Set to false if you want to always keep highlight on.
    public byte ConfigNavEscapeClearFocusWindow;                     // = false          // Pressing Escape can clear focused window as well (super set of io.ConfigNavEscapeClearFocusItem).
    public byte ConfigNavCursorVisibleAuto;                          // = true           // Using directional navigation key makes the cursor visible. Mouse click hides the cursor.
    public byte ConfigNavCursorVisibleAlways;                        // = false          // Navigation cursor is always visible.
    public byte ConfigDockingNoSplit;                                // = false          // Simplified docking mode: disable window splitting, so docking is limited to merging multiple windows together into tab-bars.
    public byte ConfigDockingNoDockingOver;                          // = false          // Simplified docking mode: disable window merging into a same tab-bar, so docking is limited to splitting windows.
    public byte ConfigDockingWithShift;                              // = false          // Enable docking with holding Shift key (reduce visual noise, allows dropping in wider space)
    public byte ConfigDockingAlwaysTabBar;                           // = false          // [BETA] [FIXME: This currently creates regression with auto-sizing and general overhead] Make every single floating window display within a docking node.
    public byte ConfigDockingTransparentPayload;                     // = false          // [BETA] Make window or viewport transparent when docking and only display docking boxes on the target viewport. Useful if rendering of multiple viewport cannot be synced. Best used with ConfigViewportsNoAutoMerge.
    public byte ConfigViewportsNoAutoMerge;                          // = false;         // Set to make all floating imgui windows always create their own viewport. Otherwise, they are merged into the main host viewports when overlapping it. May also set ImGuiViewportFlags_NoAutoMerge on individual viewport.
    public byte ConfigViewportsNoTaskBarIcon;                        // = false          // Disable default OS task bar icon flag for secondary viewports. When a viewport doesn't want a task bar icon, ImGuiViewportFlags_NoTaskBarIcon will be set on it.
    public byte ConfigViewportsNoDecoration;                         // = true           // Disable default OS window decoration flag for secondary viewports. When a viewport doesn't want window decorations, ImGuiViewportFlags_NoDecoration will be set on it. Enabling decoration can create subsequent issues at OS levels (e.g. minimum window size).
    public byte ConfigViewportsNoDefaultParent;                      // = true           // When false: set secondary viewports' ParentViewportId to main viewport ID by default. Expects the platform backend to setup a parent/child relationship between the OS windows based on this value. Some backend may ignore this. Set to true if you want viewports to automatically be parent of main viewport, otherwise all viewports will be top-level OS windows.
    public byte ConfigViewportsPlatformFocusSetsImGuiFocus;          // = true // When a platform window is focused (e.g. using Alt+Tab, clicking Platform Title Bar), apply corresponding focus on imgui windows (may clear focus/active id from imgui windows location in other platform windows). In principle this is better enabled but we provide an opt-out, because some Linux window managers tend to eagerly focus windows (e.g. on mouse hover, or even a simple window pos/size change).
    public byte ConfigDpiScaleFonts;                                 // = false          // [EXPERIMENTAL] Automatically overwrite style.FontScaleDpi when Monitor DPI changes. This will scale fonts but _NOT_ scale sizes/padding for now.
    public byte ConfigDpiScaleViewports;                             // = false          // [EXPERIMENTAL] Scale Dear ImGui and Platform Windows when Monitor DPI changes.
    public byte MouseDrawCursor;                                     // = false          // Request ImGui to draw a mouse cursor for you (if you are on a platform without a mouse cursor). Cannot be easily renamed to 'io.ConfigXXX' because this is frequently used by backend implementations.
    public byte ConfigMacOSXBehaviors;                               // = defined(__APPLE__) // Swap Cmd<>Ctrl keys + OS X style text editing cursor movement using Alt instead of Ctrl, Shortcuts using Cmd/Super instead of Ctrl, Line/Text Start and End using Cmd+Arrows instead of Home/End, Double click selects by word instead of selecting whole text, Multi-selection in lists uses Cmd/Super instead of Ctrl.
    public byte ConfigInputTrickleEventQueue;                        // = true           // Enable input queue trickling: some types of events submitted during the same frame (e.g. button down + up) will be spread over multiple frames, improving interactions with low framerates.
    public byte ConfigInputTextCursorBlink;                          // = true           // Enable blinking cursor (optional as some users consider it to be distracting).
    public byte ConfigInputTextEnterKeepActive;                      // = false          // [BETA] Pressing Enter will reactivate item and select all text (single-line only).
    public byte ConfigDragClickToInputText;                          // = false          // [BETA] Enable turning DragXXX widgets into text input with a simple mouse click-release (without moving). Not desirable on devices without a keyboard.
    public byte ConfigWindowsResizeFromEdges;                        // = true           // Enable resizing of windows from their edges and from the lower-left corner. This requires ImGuiBackendFlags_HasMouseCursors for better mouse cursor feedback. (This used to be a per-window ImGuiWindowFlags_ResizeFromAnySide flag)
    public byte ConfigWindowsMoveFromTitleBarOnly;                   // = false      // Enable allowing to move windows only when clicking on their title bar. Does not apply to windows without a title bar.
    public byte ConfigWindowsCopyContentsWithCtrlC;                  // = false      // [EXPERIMENTAL] Ctrl+C copy the contents of focused window into the clipboard. Experimental because: (1) has known issues with nested Begin/End pairs (2) text output quality varies (3) text output is in submission order rather than spatial order.
    public byte ConfigScrollbarScrollByPage;                         // = true           // Enable scrolling page by page when clicking outside the scrollbar grab. When disabled, always scroll to clicked location. When enabled, Shift+Click scrolls to clicked location.
