    public float MouseDoubleClickMaxDist;                            // = 6.0f           // Distance threshold to stay in to validate a double-click, in pixels.
    public float MouseDragThreshold;                                 // = 6.0f           // Distance threshold before considering we are dragging.
    public float KeyRepeatDelay;                                     // = 0.275f         // When holding a key/button, time before it starts repeating, in seconds (for buttons in Repeat mode, etc.).
    public float KeyRepeatRate;                                      // = 0.050f         // When holding a key/button, rate at which it repeats, in seconds.
    public byte ConfigErrorRecovery;                                 // = true       // Enable error recovery support. Some errors won't be detected and lead to direct crashes if recovery is disabled.
    public byte ConfigErrorRecoveryEnableAssert;                     // = true       // Enable asserts on recoverable error. By default call IM_ASSERT() when returning from a failing IM_ASSERT_USER_ERROR()
    public byte ConfigErrorRecoveryEnableDebugLog;                   // = true       // Enable debug log output on recoverable errors.
    public byte ConfigErrorRecoveryEnableTooltip;                    // = true       // Enable tooltip on recoverable errors. The tooltip include a way to enable asserts if they were disabled.
