    public byte WantCaptureMouseUnlessPopupClose;                    // Alternative to WantCaptureMouse: (WantCaptureMouse == true && WantCaptureMouseUnlessPopupClose == false) when a click over void is expected to close a popup.
    public ImVec2 MousePosPrev;                                      // Previous mouse position (note that MouseDelta is not necessary == MousePos-MousePosPrev, in case either position is invalid)
    public IO_MouseClickedPos_Array MouseClickedPos;                 // Position at time of clicking
    public fixed double MouseClickedTime[5];                         // Time of last click (used to figure out double-click)
    public fixed byte MouseClicked[5];                               // Mouse button went from !Down to Down (same as MouseClickedCount[x] != 0)
    public fixed byte MouseDoubleClicked[5];                         // Has mouse button been double-clicked? (same as MouseClickedCount[x] == 2)
    public fixed ushort MouseClickedCount[5];                        // == 0 (not clicked), == 1 (same as MouseClicked[]), == 2 (double-clicked), == 3 (triple-clicked) etc. when going from !Down to Down
    public fixed ushort MouseClickedLastCount[5];                    // Count successive number of clicks. Stays valid after mouse release. Reset after another click is done.
    public fixed byte MouseReleased[5];                              // Mouse button went from Down to !Down
    public fixed double MouseReleasedTime[5];                        // Time of last released (rarely used! but useful to handle delayed single-click when trying to disambiguate them from double-click).
    public fixed byte MouseDownOwned[5];                             // Track if button was clicked inside a dear imgui window or over void blocked by a popup. We don't request mouse capture from the application if click started outside ImGui bounds.
    public fixed byte MouseDownOwnedUnlessPopupClose[5];             // Track if button was clicked inside a dear imgui window.
    public byte MouseWheelRequestAxisSwap;                           // On a non-Mac system, holding Shift requests WheelY to perform the equivalent of a WheelX event. On a Mac system this is already enforced by the system.
    public byte MouseCtrlLeftAsRightClick;                           // (OSX) Set to true when the current click was a Ctrl+Click that spawned a simulated right click
    public fixed float MouseDownDuration[5];                         // Duration the mouse button has been down (0.0f == just clicked)
    public fixed float MouseDownDurationPrev[5];                     // Previous time the mouse button has been down
    public IO_MouseDragMaxDistanceAbs_Array MouseDragMaxDistanceAbs; // Maximum distance, absolute, on each axis, of how much mouse has traveled from the clicking point
    public fixed float MouseDragMaxDistanceSqr[5];                   // Squared maximum distance of how much mouse has traveled from the clicking point (used for moving thresholds)
    public float PenPressure;                                        // Touch/Pen pressure (0.0f to 1.0f, should be >0.0f only when MouseDown[0] == true). Helper storage currently unused by Dear ImGui.
    public byte AppFocusLost;                                        // Only modify via AddFocusEvent()
    public byte AppAcceptingEvents;                                  // Only modify via SetAppAcceptingEvents()
    public ushort InputQueueSurrogate;                               // For AddInputCharacterUTF16()
    public ImVector_ImWchar InputQueueCharacters;                    // Queue of _characters_ input (obtained by platform backend). Fill using AddInputCharacter() helper.
