/// <summary>
/// Optional helper to store multi-selection state + apply multi-selection requests.
/// - Used by our demos and provided as a convenience to easily implement basic multi-selection.
/// - Iterate selection with 'void* it = NULL; ImGuiID id; while (selection.GetNextSelectedItem(&amp;it, &amp;id)) { ... }'
/// Or you can check 'if (Contains(id)) { ... }' for each possible object if their number is not too high to iterate.
/// - USING THIS IS NOT MANDATORY. This is only a helper and not a required API.
/// To store a multi-selection, in your application you could:
/// - Use this helper as a convenience. We use our simple key-&gt;value ImGuiStorage as a std::set&lt;ImGuiID&gt; replacement.
/// - Use your own external storage: e.g. std::set&lt;MyObjectId&gt;, std::vector&lt;MyObjectId&gt;, interval trees, intrusively stored selection etc.
/// In ImGuiSelectionBasicStorage we:
/// - always use indices in the multi-selection API (passed to SetNextItemSelectionUserData(), retrieved in ImGuiMultiSelectIO)
/// - use the AdapterIndexToStorageId() indirection layer to abstract how persistent selection data is derived from an index.
/// - use decently optimized logic to allow queries and insertion of very large selection sets.
/// - do not preserve selection order.
/// Many combinations are possible depending on how you prefer to store your items and how you prefer to store your selection.
/// Large applications are likely to eventually want to get rid of this indirection layer and do their own thing.
/// See https://github.com/ocornut/imgui/wiki/Multi-Select for details and pseudo-code using this helper.
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct SelectionBasicStorage
{
    public int Size;                     // // Number of selected items, maintained by this helper.
    public byte PreserveOrder;           // = false  // GetNextSelectedItem() will return ordered selection (currently implemented by two additional sorts of selection. Could be improved)
    public nint UserData;                // = NULL   // User data for use by adapter function        // e.g. selection.UserData = (void*)my_items;
    public nint AdapterIndexToStorageId; // e.g. selection.AdapterIndexToStorageId = [](ImGuiSelectionBasicStorage* self, int idx) { return ((MyItems**)self->UserData)[idx]->ID; };
    public int _SelectionOrder;          // [Internal] Increasing counter to store selection order
    public Storage _Storage;             // [Internal] Selection set. Think of this as similar to e.g. std::set<ImGuiID>. Prefer not accessing directly: iterate with GetNextSelectedItem().
}

