/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct ImDrawCmd
{
    public ImVec4 ClipRect;            // 4*4  // Clipping rectangle (x1, y1, x2, y2). Subtract ImDrawData->DisplayPos to get clipping rectangle in "viewport" coordinates
    public ImTextureRef TexRef;        // 16   // Reference to a font/texture atlas (where backend called ImTextureData::SetTexID()) or to a user-provided texture ID (via e.g. ImGui::Image() calls). Both will lead to a ImTextureID value.
    public uint VtxOffset;             // 4    // Start offset in vertex buffer. ImGuiBackendFlags_RendererHasVtxOffset: always 0, otherwise may be >0 to support meshes larger than 64K vertices with 16-bit indices.
    public uint IdxOffset;             // 4    // Start offset in index buffer.
    public uint ElemCount;             // 4    // Number of indices (multiple of 3) to be rendered as triangles. Vertices are stored in the callee ImDrawList's vtx_buffer[] array, indices in idx_buffer[].
    public nint UserCallback;          // 4-8  // If != NULL, call the function instead of rendering the vertices. clip_rect and texture_id will be set normally.
    public nint UserCallbackData;      // 4-8  // Callback user data (when UserCallback != NULL). If called AddCallback() with size == 0, this is a copy of the AddCallback() argument. If called AddCallback() with size > 0, this is pointing to a buffer where data is stored.
    public int UserCallbackDataSize;   // 4 // Size of callback user data when using storage, otherwise 0.
    public int UserCallbackDataOffset; // 4 // [Internal] Offset of callback user data when using storage, otherwise -1.
}

