    public ImVec2 FramebufferScale;             // Amount of pixels for each unit of DisplaySize. Copied from viewport->FramebufferScale (== io.DisplayFramebufferScale for main viewport). Generally (1,1) on normal display, (2,2) on OSX with Retina display.
    public Viewport* OwnerViewport;             // Viewport carrying the ImDrawData instance, might be of use to the renderer (generally not).
    public ImVector_ImTextureDataPtr* Textures; // List of textures to update. Most of the times the list is shared by all ImDrawData, has only 1 texture and it doesn't need any update. This almost always points to ImGui::GetPlatformIO().Textures[]. May be overridden or set to NULL if you want to manually update textures.
}

/// <summary>
