    public ushort h; // Size of rectangle to update (in pixels)
}

/// <summary>
/// Specs and pixel storage for a texture used by Dear ImGui.
/// This is only useful for (1) core library and (2) backends. End-user/applications do not need to care about this.
/// Renderer Backends will create a GPU-side version of this.
/// Why does we store two identifiers: TexID and BackendUserData?
/// - ImTextureID    TexID           = lower-level identifier stored in ImDrawCmd. ImDrawCmd can refer to textures not created by the backend, and for which there's no ImTextureData.
/// - void*          BackendUserData = higher-level opaque storage for backend own book-keeping. Some backends may have enough with TexID and not need both.
/// In columns below: who reads/writes each fields? 'r'=read, 'w'=write, 'core'=main library, 'backend'=renderer backend
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct ImTextureData
{
    public int UniqueID;                   // w    -   // [DEBUG] Sequential index to facilitate identifying a texture when debugging/printing. Unique per atlas.
    public ImTextureStatus Status;         // rw   rw  // ImTextureStatus_OK/_WantCreate/_WantUpdates/_WantDestroy. Always use SetStatus() to modify!
    public nint BackendUserData;           // -    rw  // Convenience storage for backend. Some backends may have enough with TexID.
    public nint TexID;                     // r    w   // Backend-specific texture identifier. Always use SetTexID() to modify! The identifier will stored in ImDrawCmd::GetTexID() and passed to backend's RenderDrawData function.
    public ImTextureFormat Format;         // w    r   // ImTextureFormat_RGBA32 (default) or ImTextureFormat_Alpha8
    public int Width;                      // w    r   // Texture width
    public int Height;                     // w    r   // Texture height
    public int BytesPerPixel;              // w    r   // 4 or 1
    public byte* Pixels;                   // w    r   // Pointer to buffer holding 'Width*Height' pixels and 'Width*Height*BytesPerPixels' bytes.
    public ImTextureRect UsedRect;         // w    r   // Bounding box encompassing all past and queued Updates[].
    public ImTextureRect UpdateRect;       // w    r   // Bounding box encompassing all queued Updates[].
    public ImVector_ImTextureRect Updates; // w    r   // Array of individual updates.
    public int UnusedFrames;               // w    r   // In order to facilitate handling Status==WantDestroy in some backend: this is a count successive frames where the texture was not used. Always >0 when Status==WantDestroy.
    public ushort RefCount;                // w    r   // Number of contexts using this texture. Used during backend shutdown.
    public byte UseColors;                 // w    r   // Tell whether our texture data is known to use colors (rather than just white + alpha).
    public byte WantDestroyNextFrame;      // rw   -   // [Internal] Queued to set ImTextureStatus_WantDestroy next frame. May still be used in the current frame.
}

/// <summary>
/// A font input/source (we may rename this to ImFontSource in the future)
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct ImFontConfig
{
    public fixed byte Name[40];        // <auto>   // Name (strictly to ease debugging, hence limited size buffer)
    public nint FontData;              // // TTF/OTF data
    public int FontDataSize;           // // TTF/OTF data size
    public byte FontDataOwnedByAtlas;  // true     // TTF/OTF data ownership taken by the owner ImFontAtlas (will delete memory itself). SINCE 1.92, THE DATA NEEDS TO PERSIST FOR WHOLE DURATION OF ATLAS.
    public byte MergeMode;             // false    // Merge into previous ImFont, so you can combine multiple inputs font into one ImFont (e.g. ASCII font + icons + Japanese glyphs). You may want to use GlyphOffset.y when merge font of different heights.
    public byte PixelSnapH;            // false    // Align every glyph AdvanceX to pixel boundaries. Prevents fractional font size from working correctly! Useful e.g. if you are merging a non-pixel aligned font with the default font. If enabled, OversampleH/V will default to 1.
    public sbyte OversampleH;          // 0 (2)    // Rasterize at higher quality for sub-pixel positioning. 0 == auto == 1 or 2 depending on size. Note the difference between 2 and 3 is minimal. You can reduce this to 1 for large glyphs save memory. Read https://github.com/nothings/stb/blob/master/tests/oversample/README.md for details.
    public sbyte OversampleV;          // 0 (1)    // Rasterize at higher quality for sub-pixel positioning. 0 == auto == 1. This is not really useful as we don't use sub-pixel positions on the Y axis.
    public ushort EllipsisChar;        // 0        // Explicitly specify Unicode codepoint of ellipsis character. When fonts are being merged first specified ellipsis will be used.
    public float SizePixels;           // // Output size in pixels for rasterizer (more or less maps to the resulting font height).
    public ushort* GlyphRanges;        // NULL     // *LEGACY* THE ARRAY DATA NEEDS TO PERSIST AS LONG AS THE FONT IS ALIVE. Pointer to a user-provided list of Unicode range (2 value per range, values are inclusive, zero-terminated list).
    public ushort* GlyphExcludeRanges; // NULL     // Pointer to a small user-provided list of Unicode ranges (2 value per range, values are inclusive, zero-terminated list). This is very close to GlyphRanges[] but designed to exclude ranges from a font source, when merging fonts with overlapping glyphs. Use "Input Glyphs Overlap Detection Tool" to find about your overlapping ranges.
    public ImVec2 GlyphOffset;         // 0, 0     // Offset (in pixels) all glyphs from this font input. Absolute value for default size, other sizes will scale this value.
    public float GlyphMinAdvanceX;     // 0        // Minimum AdvanceX for glyphs, set Min to align font icons, set both Min/Max to enforce mono-space font. Absolute value for default size, other sizes will scale this value.
    public float GlyphMaxAdvanceX;     // FLT_MAX  // Maximum AdvanceX for glyphs
    public float GlyphExtraAdvanceX;   // 0        // Extra spacing (in pixels) between glyphs. Please contact us if you are using this. // FIXME-NEWATLAS: Intentionally unscaled
    public uint FontNo;                // 0        // Index of font within TTF/OTF file
    public uint FontLoaderFlags;       // 0        // Settings for custom font builder. THIS IS BUILDER IMPLEMENTATION DEPENDENT. Leave as zero if unsure.
    public float RasterizerMultiply;   // 1.0f     // Linearly brighten (>1.0f) or darken (<1.0f) font output. Brightening small fonts may be a good workaround to make them more readable. This is a silly thing we may remove in the future.
    public float RasterizerDensity;    // 1.0f     // [LEGACY: this only makes sense when ImGuiBackendFlags_RendererHasTextures is not supported] DPI scale multiplier for rasterization. Not altering other font metrics: makes it easy to swap between e.g. a 100% and a 400% fonts for a zooming display, or handle Retina screen. IMPORTANT: If you change this it is expected that you increase/decrease font scale roughly to the inverse of this, otherwise quality may look lowered.
    public float ExtraSizeScale;       // 1.0f     // Extra rasterizer scale over SizePixels.
    public ImFontFlags Flags;          // Font flags (don't use just yet, will be exposed in upcoming 1.92.X updates)
    public ImFont* DstFont;            // Target font (as we merging fonts, multiple ImFontConfig may target the same font)
    public ImFontLoader* FontLoader;   // Custom font backend for this source (default source is the one stored in ImFontAtlas)
    public nint FontLoaderData;        // Font loader opaque storage (per font config)
}

