/// <summary>
/// Load and rasterize multiple TTF/OTF fonts into a same texture. The font atlas will build a single texture holding:
/// - One or more fonts.
/// - Custom graphics data needed to render the shapes needed by Dear ImGui.
/// - Mouse cursor shapes for software cursor rendering (unless setting 'Flags |= ImFontAtlasFlags_NoMouseCursors' in the font atlas).
/// - If you don't call any AddFont*** functions, the default font embedded in the code will be loaded for you.
/// It is the rendering backend responsibility to upload texture into your graphics API:
/// - ImGui_ImplXXXX_RenderDrawData() functions generally iterate platform_io-&gt;Textures[] to create/update/destroy each ImTextureData instance.
/// - Backend then set ImTextureData's TexID and BackendUserData.
/// - Texture id are passed back to you during rendering to identify the texture. Read FAQ entry about ImTextureID/ImTextureRef for more details.
/// Legacy path:
/// - Call Build() + GetTexDataAsAlpha8() or GetTexDataAsRGBA32() to build and retrieve pixels data.
/// - Call SetTexID(my_tex_id); and pass the pointer/identifier to your texture in a format natural to your graphics API.
/// Common pitfalls:
/// - If you pass a 'glyph_ranges' array to AddFont*** functions, you need to make sure that your array persists up until the
/// atlas is build (when calling GetTexData*** or Build()). We only copy the pointer, not the data.
/// - Important: By default, AddFontFromMemoryTTF() takes ownership of the data. Even though we are not writing to it, we will free the pointer on destruction.
/// You can set font_cfg-&gt;FontDataOwnedByAtlas=false to keep ownership of your data and it won't be freed,
/// - Even though many functions are suffixed with "TTF", OTF data is supported just as well.
/// - This is an old API and it is currently awkward for those and various other reasons! We will address them in the future!
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct ImFontAtlas
{
    public ImFontAtlasFlags Flags;                               // Build flags (see ImFontAtlasFlags_)
    public ImTextureFormat TexDesiredFormat;                     // Desired texture format (default to ImTextureFormat_RGBA32 but may be changed to ImTextureFormat_Alpha8).
    public int TexGlyphPadding;                                  // FIXME: Should be called "TexPackPadding". Padding between glyphs within texture in pixels. Defaults to 1. If your rendering method doesn't rely on bilinear filtering you may set this to 0 (will also need to set AntiAliasedLinesUseTex = false).
    public int TexMinWidth;                                      // Minimum desired texture width. Must be a power of two. Default to 512.
    public int TexMinHeight;                                     // Minimum desired texture height. Must be a power of two. Default to 128.
    public int TexMaxWidth;                                      // Maximum desired texture width. Must be a power of two. Default to 8192.
    public int TexMaxHeight;                                     // Maximum desired texture height. Must be a power of two. Default to 8192.
    public nint UserData;                                        // Store your own atlas related user-data (if e.g. you have multiple font atlas).
    public ImTextureRef TexRef;                                  // Latest texture identifier == TexData->GetTexRef().
    public ImTextureData* TexData;                               // Latest texture.
    public ImVector_ImTextureDataPtr TexList;                    // Texture list (most often TexList.Size == 1). TexData is always == TexList.back(). DO NOT USE DIRECTLY, USE GetDrawData().Textures[]/GetPlatformIO().Textures[] instead!
    public byte Locked;                                          // Marked as locked during ImGui::NewFrame()..EndFrame() scope if TexUpdates are not supported. Any attempt to modify the atlas will assert.
    public byte RendererHasTextures;                             // Copy of (BackendFlags & ImGuiBackendFlags_RendererHasTextures) from supporting context.
    public byte TexIsBuilt;                                      // Set when texture was built matching current font input. Mostly useful for legacy IsBuilt() call.
    public byte TexPixelsUseColors;                              // Tell whether our texture data is known to use colors (rather than just alpha channel), in order to help backend select a format or conversion process.
    public ImVec2 TexUvScale;                                    // = (1.0f/TexData->TexWidth, 1.0f/TexData->TexHeight). May change as new texture gets created.
    public ImVec2 TexUvWhitePixel;                               // Texture coordinates to a white pixel. May change as new texture gets created.
    public ImVector_ImFontPtr Fonts;                             // Hold all the fonts returned by AddFont*. Fonts[0] is the default font upon calling ImGui::NewFrame(), use ImGui::PushFont()/PopFont() to change the current font.
    public ImVector_ImFontConfig Sources;                        // Source/configuration data
    public ImFontAtlas_TexUvLines_Array TexUvLines;              // UVs for baked anti-aliased lines
    public int TexNextUniqueID;                                  // Next value to be stored in TexData->UniqueID
    public int FontNextUniqueID;                                 // Next value to be stored in ImFont->FontID
    public ImVector_ImDrawListSharedDataPtr DrawListSharedDatas; // List of users for this atlas. Typically one per Dear ImGui context.
    public ImFontAtlasBuilder* Builder;                          // Opaque interface to our data that doesn't need to be public and may be discarded when rebuilding.
    public ImFontLoader* FontLoader;                             // Font loader opaque interface (default to use FreeType when IMGUI_ENABLE_FREETYPE is defined, otherwise default to use stb_truetype). Use SetFontLoader() to change this at runtime.
    public byte* FontLoaderName;                                 // Font loader name (for display e.g. in About box) == FontLoader->Name
    public nint FontLoaderData;                                  // Font backend opaque storage
    public uint FontLoaderFlags;                                 // Shared flags (for all fonts) for font loader. THIS IS BUILD IMPLEMENTATION DEPENDENT (e.g. Per-font override is also available in ImFontConfig).
    public int RefCount;                                         // Number of contexts using this atlas
    public Context* OwnerContext;                                // Context which own the atlas will be in charge of updating and destroying it.
}

/// <summary>
/// Font runtime data for a given size
/// Important: pointers to ImFontBaked are only valid for the current frame.
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct ImFontBaked
{
    public ImVector_float IndexAdvanceX; // 12-16 // out // Sparse. Glyphs->AdvanceX in a directly indexable way (cache-friendly for CalcTextSize functions which only this info, and are often bottleneck in large UI).
    public float FallbackAdvanceX;       // 4     // out // FindGlyph(FallbackChar)->AdvanceX
    public float Size;                   // 4     // in  // Height of characters/line, set during loading (doesn't change after loading)
    public float RasterizerDensity;      // 4     // in  // Density this is baked at
    public ImVector_ImU16 IndexLookup;   // 12-16 // out // Sparse. Index glyphs by Unicode code-point.
    public ImVector_ImFontGlyph Glyphs;  // 12-16 // out // All glyphs.
    public int FallbackGlyphIndex;       // 4     // out // Index of FontFallbackChar
    public float Ascent;                 // 4+4   // out // Ascent: distance from top to bottom of e.g. 'A' [0..FontSize] (unscaled)
    public float Descent;                // 4+4   // out // Ascent: distance from top to bottom of e.g. 'A' [0..FontSize] (unscaled)
    public uint MetricsTotalSurface;     // 3  // out // Total surface in pixels to get an idea of the font rasterization/texture cost (not exact, we approximate the cost of padding between glyphs)
    public uint WantDestroy;             // 0  //     // Queued for destroy
    public uint LoadNoFallback;          // 0  //     // Disable loading fallback in lower-level calls.
    public uint LoadNoRenderOnLayout;    // 0  //     // Enable a two-steps mode where CalcTextSize() calls will load AdvanceX *without* rendering/packing glyphs. Only advantageous if you know that the glyph is unlikely to actually be rendered, otherwise it is slower because we'd do one query on the first CalcTextSize and one query on the first Draw.
    public int LastUsedFrame;            // 4  //     // Record of that time this was bounds
    public uint BakedId;                 // 4     //     // Unique ID for this baked storage
    public ImFont* OwnerFont;            // 4-8   // in  // Parent font
    public nint FontLoaderDatas;         // 4-8   //     // Font loader opaque storage (per baked font * sources): single contiguous buffer allocated by imgui, passed to loader.
}

/// <summary>
/// Font runtime data and rendering
/// - ImFontAtlas automatically loads a default embedded font for you if you didn't load one manually.
/// - Since 1.92.0 a font may be rendered as any size! Therefore a font doesn't have one specific size.
/// - Use 'font-&gt;GetFontBaked(size)' to retrieve the ImFontBaked* corresponding to a given size.
/// - If you used g.Font + g.FontSize (which is frequent from the ImGui layer), you can use g.FontBaked as a shortcut, as g.FontBaked == g.Font-&gt;GetFontBaked(g.FontSize).
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct ImFont
{
    public ImFontBaked* LastBaked;           // 4-8   // Cache last bound baked. NEVER USE DIRECTLY. Use GetFontBaked().
    public ImFontAtlas* OwnerAtlas;          // 4-8   // What we have been loaded into.
    public ImFontFlags Flags;                // 4     // Font flags.
    public float CurrentRasterizerDensity;   // Current rasterizer density. This is a varying state of the font.
    public uint FontId;                      // Unique identifier for the font
    public float LegacySize;                 // 4     // in  // Font size passed to AddFont(). Use for old code calling PushFont() expecting to use that size. (use ImGui::GetFontBaked() to get font baked at current bound size).
    public ImVector_ImFontConfigPtr Sources; // 16    // in  // List of sources. Pointers within OwnerAtlas->Sources[]
    public ushort EllipsisChar;              // 2-4   // out // Character used for ellipsis rendering ('...'). If you ever want to temporarily swap this for an alternative/dummy char, make sure to clear EllipsisAutoBake.
    public ushort FallbackChar;              // 2-4   // out // Character used if a glyph isn't found (U+FFFD, '?')
    public fixed byte Used8kPagesMap[17];    // 1 bytes if ImWchar=ImWchar16, 17 bytes if ImWchar==ImWchar32. Store 1-bit for each block of 8K codepoints that has one active glyph. This is mainly used to facilitate iterations across all used codepoints.
    public byte EllipsisAutoBake;            // 1     //     // Mark when the "..." glyph (== EllipsisChar) needs to be generated by combining multiple '.'.
    public Storage RemapPairs;               // 16    //     // Remapping pairs when using AddRemapChar(), otherwise empty.
}

/// <summary>
/// - Currently represents the Platform Window created by the application which is hosting our Dear ImGui windows.
/// - With multi-viewport enabled, we extend this concept to have multiple active viewports.
/// - In the future we will extend this concept further to also represent Platform Monitor and support a "no main platform window" operation mode.
/// - About Main Area vs Work Area:
/// - Main Area = entire viewport.
/// - Work Area = entire viewport minus sections used by main menu bars (for platform windows), or by task bar (for platform monitor).
/// - Windows are generally trying to stay within the Work Area of their host viewport.
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public unsafe partial struct Viewport
{
    public uint ID;                    // Unique identifier for the viewport
    public ViewportFlags Flags;        // See ImGuiViewportFlags_
    public ImVec2 Pos;                 // Main Area: Position of the viewport (Dear ImGui coordinates are the same as OS desktop/native coordinates)
    public ImVec2 Size;                // Main Area: Size of the viewport.
    public ImVec2 FramebufferScale;    // Density of the viewport for Retina display (always 1,1 on Windows, may be 2,2 etc on macOS/iOS). This will affect font rasterizer density.
    public ImVec2 WorkPos;             // Work Area: Position of the viewport minus task bars, menus bars, status bars (>= Pos)
    public ImVec2 WorkSize;            // Work Area: Size of the viewport minus task bars, menu bars, status bars (<= Size)
    public float DpiScale;             // 1.0f = 96 DPI = No extra scale.
    public uint ParentViewportId;      // (Advanced) 0: no parent. Instruct the platform backend to setup a parent/child relationship between platform windows.
    public Viewport* ParentViewport;   // (Advanced) Direct shortcut to ImGui::FindViewportByID(ParentViewportId). NULL: no parent.
    public ImDrawData* DrawData;       // The ImDrawData corresponding to this viewport. Valid after Render() and until the next call to NewFrame().
    public nint RendererUserData;      // void* to hold custom data structure for the renderer (e.g. swap chain, framebuffers etc.). generally set by your Renderer_CreateWindow function.
    public nint PlatformUserData;      // void* to hold custom data structure for the OS / platform (e.g. windowing info, render context). generally set by your Platform_CreateWindow function.
    public nint PlatformHandle;        // void* to hold higher-level, platform window handle (e.g. HWND for Win32 backend, Uint32 WindowID for SDL, GLFWWindow* for GLFW), for FindViewportByPlatformHandle().
    public nint PlatformHandleRaw;     // void* to hold lower-level, platform-native window handle (always HWND on Win32 platform, unused for other platforms).
    public byte PlatformWindowCreated; // Platform window has been created (Platform_CreateWindow() has been called). This is false during the first frame where a viewport is being created.
    public byte PlatformRequestMove;   // Platform window requested move (e.g. window was moved by the OS / host window manager, authoritative position will be OS window position)
    public byte PlatformRequestResize; // Platform window requested resize (e.g. window was resized by the OS / host window manager, authoritative size will be OS window size)
    public byte PlatformRequestClose;  // Platform window requested closure (e.g. window was moved by the OS / host window manager, e.g. pressing ALT-F4)
}

